		end
	end)

	-- Auto-save loop: periodically saves the active config so it
	-- persists between sessions (load it next time with the Load button)
	task.spawn(function()
		while true do
			task.wait(30)
			if autoSaveEnabled and activeRow then
				local n = SaveText.Text
				if n ~= "Save" and n ~= "" then
					SaveNamedConfig(n)
				end
			end
		end
	end)

