						RowBtn.MouseButton1Click:Connect(function()
							selected = opt
							TextDefault.Text = opt
							updateCheckmarks()
							closeDropdown2()
							if callback then callback(opt) end
						end)
						SelBtn.MouseButton1Click:Connect(function()
							selected = opt
							TextDefault.Text = opt
							updateCheckmarks()
							closeDropdown2()
							if callback then callback(opt) end
						end)
					end

					-- Open button (invisible overlay on the row)
